import{r as e}from"./index-BzZSvCsJ.js";var t={async getAchievements(){return(await e.get(`/academy/achievements`)).data.achievements},async getBadges(){return(await e.get(`/academy/badges`)).data.badges},async getMilestones(){return(await e.get(`/academy/milestones`)).data.milestones},async getAchievementsAdmin(){return(await e.get(`/admin/academy/achievements`)).data.achievements},async createAchievement(t){return(await e.post(`/admin/academy/achievements`,t)).data.achievement},async updateAchievement(t,n){return(await e.put(`/admin/academy/achievements/${t}`,n)).data.achievement},async deleteAchievement(t){await e.delete(`/admin/academy/achievements/${t}`)},async getBadgesAdmin(){return(await e.get(`/admin/academy/badges`)).data.badges},async createBadge(t){return(await e.post(`/admin/academy/badges`,t)).data.badge},async updateBadge(t,n){return(await e.put(`/admin/academy/badges/${t}`,n)).data.badge},async deleteBadge(t){await e.delete(`/admin/academy/badges/${t}`)}};export{t};